#include <stdio.h>

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, Wmax; scanf("%d %d", &N, &Wmax);
        int W[1001];
        int V[1001];
        for (int i = 1; i <= N; ++i) {
            scanf("%d %d", &W[i], &V[i]);
        }
        int dp[1001] = {0};
        for (int i = 1; i <= N; ++i) {
            for (int w = Wmax; w >= W[i]; --w) {
                dp[w] = max(dp[w], dp[w - W[i]] + V[i]);
            }
        }
        printf("%d\n", dp[Wmax]);
    }
    return 0;
}

