import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it); Wmax = next(it)
        dp = [0] * (Wmax + 1)
        for _ in range(N):
            wi = next(it); vi = next(it)
            for w in range(Wmax, wi - 1, -1):
                if dp[w - wi] + vi > dp[w]:
                    dp[w] = dp[w - wi] + vi
        out.append(str(dp[Wmax]))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

