    const N = data[idx++];
    const Wmax = data[idx++];
    const dp = new Array(Wmax + 1).fill(0);
    for (let i = 0; i < N; i++) {
        const wi = data[idx++];
        const vi = data[idx++];
        for (let w = Wmax; w >= wi; w--) {
            const cand = dp[w - wi] + vi;
            if (cand > dp[w]) dp[w] = cand;
        }
    }
    outputs.push(String(dp[Wmax]));
